pub enum EventType {
    ChunksIndexed,
    SearchPerformed,
    IngestionStarted,
    IngestionCompleted,
    MergeCompleted,
    MergeFailed,
    EntryCommitted,
    SessionOpened,
    SessionClosed,
    GcCompleted,
}
impl Event {
    pub fn new(event_type: EventType, data: serde_json::Value) -> Self {
        Self {
            ts: Utc::now(),
            event_type,
            data,
        }
    }
}
